import React, { useState, useMemo, useRef, useEffect } from 'react';

// ============================================
// Design Tokens
// ============================================
const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    positive: '#10b981',
    negative: '#f43f5e',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const featureColors = ['#f472b6', '#38bdf8'];

// ============================================
// Feature Scaling Calculations
// ============================================
function computeScaling(data) {
  const rows = data.length;
  const cols = data[0].length;

  // Per-column stats
  const stats = [];
  for (let j = 0; j < cols; j++) {
    const col = data.map(row => row[j]);
    const mean = col.reduce((a, b) => a + b, 0) / rows;
    const variance = col.reduce((a, b) => a + (b - mean) ** 2, 0) / rows;
    const std = Math.sqrt(variance);
    const min = Math.min(...col);
    const max = Math.max(...col);
    stats.push({ mean, std, min, max });
  }

  // Standardized
  const standardized = data.map(row =>
    row.map((val, j) => Math.round(((val - stats[j].mean) / stats[j].std) * 10000) / 10000)
  );

  // Min-Max Normalized
  const normalized = data.map(row =>
    row.map((val, j) => {
      const range = stats[j].max - stats[j].min;
      return range === 0 ? 0 : Math.round(((val - stats[j].min) / range) * 10000) / 10000;
    })
  );

  return { stats, standardized, normalized };
}

