function NumberLineViz({ original, transformed, stats, featureIdx, method, step }) {
  const canvasRef = useRef(null);
  const width = 280;
  const height = 100;
  const padding = 30;
  const color = featureColors[featureIdx];

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, width, height);

    // Determine scale based on method
    let minVal, maxVal, tickLabels;
    if (step === 1) {
      // Original scale
      minVal = stats.min - (stats.max - stats.min) * 0.2;
      maxVal = stats.max + (stats.max - stats.min) * 0.2;
      tickLabels = [stats.min, stats.mean, stats.max];
    } else if (method === 'standardized') {
      minVal = -2;
      maxVal = 2;
      tickLabels = [-2, -1, 0, 1, 2];
    } else {
      minVal = -0.2;
      maxVal = 1.2;
      tickLabels = [0, 0.5, 1];
    }

    const scaleX = (v) => padding + ((v - minVal) / (maxVal - minVal)) * (width - 2 * padding);

    // Draw axis line
    ctx.strokeStyle = theme.colors.textMuted;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(padding, height / 2);
    ctx.lineTo(width - padding, height / 2);
    ctx.stroke();

    // Draw ticks and labels
    ctx.fillStyle = theme.colors.textMuted;
    ctx.font = '9px JetBrains Mono';
    ctx.textAlign = 'center';
    tickLabels.forEach(val => {
      const x = scaleX(val);
      ctx.beginPath();
      ctx.moveTo(x, height / 2 - 5);
      ctx.lineTo(x, height / 2 + 5);
      ctx.stroke();
      ctx.fillText(typeof val === 'number' ? (Number.isInteger(val) ? val : val.toFixed(1)) : val, x, height / 2 + 18);
    });

    // Draw reference lines for standardized (mean at 0)
    if (step > 1 && method === 'standardized') {
      ctx.strokeStyle = `${theme.colors.yellow}50`;
      ctx.setLineDash([4, 4]);
      ctx.beginPath();
      ctx.moveTo(scaleX(0), height / 2 - 20);
      ctx.lineTo(scaleX(0), height / 2 + 20);
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.fillStyle = theme.colors.yellow;
      ctx.fillText('mean=0', scaleX(0), height / 2 - 25);
    }

    // Draw reference for min-max (0 and 1)
    if (step > 1 && method === 'normalized') {
      ctx.strokeStyle = `${theme.colors.green}50`;
      ctx.setLineDash([4, 4]);
      [0, 1].forEach(v => {
        ctx.beginPath();
        ctx.moveTo(scaleX(v), height / 2 - 20);
        ctx.lineTo(scaleX(v), height / 2 + 20);
        ctx.stroke();
      });
      ctx.setLineDash([]);
      ctx.fillStyle = theme.colors.green;
      ctx.fillText('min=0', scaleX(0), height / 2 - 25);
      ctx.fillText('max=1', scaleX(1), height / 2 - 25);
    }

    // Draw data points
    const values = step === 1 ? original : transformed;
    values.forEach((val, i) => {
      const x = scaleX(val);

      // Draw point
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.arc(x, height / 2, 8, 0, Math.PI * 2);
      ctx.fill();

      // Label
      ctx.fillStyle = theme.colors.text;
      ctx.font = '10px JetBrains Mono';
      ctx.fillText(val.toFixed(2), x, height / 2 - 15);
    });

  }, [original, transformed, stats, step, method, color]);

  return (
    <canvas
      ref={canvasRef}
      width={width}
      height={height}
      style={{ borderRadius: '8px', display: 'block' }}
    />
  );
}

