function ScatterComparison({ data, transformed, step, method }) {
  const canvasRef = useRef(null);
  const size = 180;
  const padding = 25;

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, size, size);

    const values = step === 1 ? data : transformed;

    // Determine scale
    let xMin, xMax, yMin, yMax;
    if (step === 1) {
      const allX = data.map(r => r[0]);
      const allY = data.map(r => r[1]);
      xMin = Math.min(...allX) - 1;
      xMax = Math.max(...allX) + 1;
      yMin = Math.min(...allY) - 1;
      yMax = Math.max(...allY) + 1;
    } else if (method === 'standardized') {
      xMin = yMin = -2;
      xMax = yMax = 2;
    } else {
      xMin = yMin = -0.2;
      xMax = yMax = 1.2;
    }

    const scaleX = (v) => padding + ((v - xMin) / (xMax - xMin)) * (size - 2 * padding);
    const scaleY = (v) => size - padding - ((v - yMin) / (yMax - yMin)) * (size - 2 * padding);

    // Grid
    ctx.strokeStyle = theme.colors.border;
    ctx.lineWidth = 1;
    for (let i = 0; i <= 4; i++) {
      const x = padding + (i / 4) * (size - 2 * padding);
      const y = padding + (i / 4) * (size - 2 * padding);
      ctx.beginPath();
      ctx.moveTo(x, padding);
      ctx.lineTo(x, size - padding);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(padding, y);
      ctx.lineTo(size - padding, y);
      ctx.stroke();
    }

    // Axes
    ctx.strokeStyle = theme.colors.textMuted;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(padding, size - padding);
    ctx.lineTo(size - padding, size - padding);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(padding, padding);
    ctx.lineTo(padding, size - padding);
    ctx.stroke();

    // Points
    values.forEach((row) => {
      ctx.fillStyle = theme.colors.primary;
      ctx.beginPath();
      ctx.arc(scaleX(row[0]), scaleY(row[1]), 6, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = theme.colors.text;
      ctx.lineWidth = 2;
      ctx.stroke();
    });

    // Axis labels
    ctx.fillStyle = featureColors[0];
    ctx.font = '10px JetBrains Mono';
    ctx.textAlign = 'center';
    ctx.fillText('Feature 1', size / 2, size - 5);
    ctx.save();
    ctx.translate(8, size / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillStyle = featureColors[1];
    ctx.fillText('Feature 2', 0, 0);
    ctx.restore();

  }, [data, transformed, step, method]);

  return (
    <canvas
      ref={canvasRef}
      width={size}
      height={size}
      style={{ borderRadius: '8px', display: 'block' }}
    />
  );
}

