          ))}
        </div>

        {/* Main Card */}
        <div style={{ background: theme.colors.surfaceAlt, borderRadius: '12px', padding: '16px' }}>

          {/* Visualizations */}
          <div style={{ display: 'flex', gap: '16px', marginBottom: '12px' }}>
            {/* Number Lines */}
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: '9px', color: theme.colors.textMuted, marginBottom: '6px', textAlign: 'center' }}>
                {step === 1 ? 'ORIGINAL VALUES' : step === 2 ? 'STANDARDIZED (mean=0, std=1)' : step === 3 ? 'NORMALIZED (0 to 1)' : 'FEATURE DISTRIBUTIONS'}
              </div>
              {[0, 1].map(featureIdx => (
                <div key={featureIdx} style={{ marginBottom: '8px' }}>
